// Live product array ? starts with fallback, replaced by API data if available
let PRODUCTS = [...FALLBACK_PRODUCTS];

const _BUNDLE_CACHE_KEY = 'getotts_catalog_cache';
const _BUNDLE_CACHE_TTL = 15 * 60 * 1000; // 15 minutes

async function syncCatalogFromCloud() {
    // 1. Try sessionStorage cache first
    try {
        const cached = sessionStorage.getItem(_BUNDLE_CACHE_KEY);
        if (cached) {
            const { data, ts } = JSON.parse(cached);
            if (Date.now() - ts < _BUNDLE_CACHE_TTL && data && data.length > 0) {
                PRODUCTS = data;
                console.log('[Catalog] Loaded', PRODUCTS.length, 'products from cache');
                return;
            }
        }
    } catch (e) { /* cache corrupt ? fetch fresh */ }

    // 2. Fetch from API
    try {
        const API_BASE = (window.GETOTTS_CONFIG && window.GETOTTS_CONFIG.API_BASE) || 'https://api.getotts.com/api/v1';
        const res = await fetch(API_BASE + '/public/catalog');
        const data = await res.json();
        if (data.success && data.catalog && data.catalog.length > 0) {
            const validCatalog = data.catalog.filter(p => p && p.id && p.name && Array.isArray(p.variants) && p.variants.length > 0);
            if (validCatalog.length > 0) {
                // MERGE: API products take priority, but fill in missing ones from fallback
                const apiSlugs = new Set(validCatalog.map(p => p.slug).filter(Boolean));
                const apiIds = new Set(validCatalog.map(p => p.id));
                const merged = [...validCatalog];
                
                for (const fp of FALLBACK_PRODUCTS) {
                    if (!apiSlugs.has(fp.id) && !apiIds.has(fp.id)) {
                        merged.push(fp);
                    }
                }
                
                PRODUCTS = merged;
                console.log(`[Catalog] Merged: ${validCatalog.length} from API + ${merged.length - validCatalog.length} from fallback = ${merged.length} total`);
                // 3. Cache for future page loads
                try {
                    sessionStorage.setItem(_BUNDLE_CACHE_KEY, JSON.stringify({ data: merged, ts: Date.now() }));
                } catch (e) { /* storage full */ }
            } else {
                console.warn('[Catalog] API returned only invalid/null products, keeping fallback');
            }
        } else {
            console.log('[Catalog] DB empty, using built-in fallback catalog');
        }
    } catch(e) {
        console.warn('[Catalog] API unreachable, using fallback:', e.message);
    }
}

/* ================================================
   HELPER FUNCTIONS
   ================================================ */

/** Get all products merged with admin overrides */
function getAllProducts() {
    const overrides = JSON.parse(localStorage.getItem('getotts_admin_products') || '{}');
    
    let allProducts = PRODUCTS.map(p => {
        const ov = overrides[p.id];
        if (!ov) return p;
        // Skip old-format v2 overrides
        if (ov.planTypes || ov.prices) return p;
        const merged = { ...p, ...ov };
        if (ov.variants) merged.variants = ov.variants;
        if (Array.isArray(ov.features)) merged.features = p.features;
        return merged;
    });
    
    // Append custom products created in admin
    const baseIds = new Set(PRODUCTS.map(p => p.id));
    for (const [id, ov] of Object.entries(overrides)) {
        if (!baseIds.has(id) && !(ov.planTypes || ov.prices)) {
            allProducts.push({
                id, name: ov.name || 'New Product', category: ov.category || 'other',
                img: ov.img || '', emoji: ov.emoji || '??', description: ov.description || '',
                isHot: ov.isHot || false, gradient: ov.gradient || '',
                features: ov.features || { shared: [] }, variants: ov.variants || [],
                delivery_mode: ov.delivery_mode || 'automatic', isActive: ov.isActive !== false
            });
        }
    }
    
    return allProducts;
}

function getProductsByCategory(category) {
    return getAllProducts().filter(p => p.category === category && p.isActive !== false);
}

function getProductById(id) {
    return getAllProducts().find(p => p.id === id);
}

function getDefaultVariant(product) {
    if (!product || !product.variants || product.variants.length === 0) {
        return { sku: (product ? product.id : 'unknown') + '-base', accessType: 'shared', quality: null, duration: 1, durationLabel: '1 Month', price: 99, originalPrice: 199, stock: 10 };
    }
    return product.variants[0];
}

function getAccessTypes(product) {
    if (!product || !product.variants) return [];
    const types = [...new Set(product.variants.map(v => v.accessType))].filter(Boolean);
    return types.length ? types : ['shared'];
}

function getQualities(product, accessType) {
    if (!product || !product.variants) return [];
    return [...new Set(product.variants.filter(v => !accessType || v.accessType === accessType).map(v => v.quality))].filter(Boolean);
}

function getDurations(product, accessType, quality) {
    if (!product || !product.variants) return [];
    return product.variants
        .filter(v => (!accessType || v.accessType === accessType) && (!quality || v.quality === quality))
        .map(v => v.duration)
        .filter((v, i, a) => a.indexOf(v) === i)
        .sort((a, b) => a - b);
}

function getVariant(sku) {
    for (const p of getAllProducts()) {
        if (p.variants) {
            const v = p.variants.find(vx => vx.sku === sku);
            if (v) return { product: p, variant: v };
        }
        // Fallback for custom products without defined variants that use the '-base' SKU
        if (sku === p.id + '-base') {
            return { product: p, variant: getDefaultVariant(p) };
        }
    }
    return null;
}

function findVariant(product, accessType, quality, months) {
    if (!product || !product.variants) return null;
    return product.variants.find(v =>
        (!accessType || v.accessType === accessType) &&
        (!quality || v.quality === quality) &&
        (!months || v.duration == months)
    ) || product.variants[0];
}

function getDiscountLevel(price) {
    if (price >= 1500) return 'mega';
    if (price >= 500) return 'super';
    return 'good';
}


/* ============================================
   GetOTTs v4 ? Premium White + Gold Design
   Variant-aware Product Cards + Cart + Animations
   ============================================ */

document.addEventListener('DOMContentLoaded', async () => {
    if (window.lucide) lucide.createIcons();

    // Update login/dashboard button immediately (before any async work)
    try { initHeader(); } catch(e) { console.warn('[INIT] initHeader error:', e); }

    // Fetch headless catalog from backend
    try {
        if (typeof syncCatalogFromCloud === 'function') {
            await syncCatalogFromCloud();
        }
    } catch(e) { console.warn('[INIT] Catalog sync error:', e); }

    try { renderAllProducts(); } catch(e) { console.warn('[INIT] renderAllProducts error:', e); }
    try { initPlanSwitch(); } catch(e) {}
    try { initComboBuilder(); } catch(e) {}
    try { initStatusGrid(); } catch(e) {}
    try { initReviews(); } catch(e) {}
    try { initFAQ(); } catch(e) {}
    try { initSearch(); } catch(e) {}
    // try { initToast(); } catch(e) {}
    try { initLazyVideos(); } catch(e) {}
    try { initScrollAnimations(); } catch(e) {}

    // Signal to site-editor.js that all products are now rendered
    window.dispatchEvent(new CustomEvent('productsRendered'));
});

/* ================================================
   RENDER PRODUCTS BY CATEGORY
   ================================================ */
// Global: tracks selected variant per product card
const cardSelections = {};

function renderAllProducts() {
    renderHotDeals();
    renderCategory('streamingGrid', 'streaming');
    renderCategory('musicGrid', 'music');
    renderCategory('aiGrid', 'ai');
    renderCategory('vpnGrid', 'vpn');
    renderCategory('giftCardsGrid', 'gift-cards');
    
    // Always restore admin edit buttons if edit mode is active (prevents disappearance after sync/saves)
    if (typeof window !== 'undefined' && window.editModeActive && typeof window.addEditButtons === 'function') {
        setTimeout(window.addEditButtons, 50);
    }
}

function renderHotDeals() {
    const grid = document.getElementById('hotDealsGrid');
    if (!grid) return;

    const allActive = getAllProducts().filter(p => p.isActive !== false && p.variants && p.variants.length > 0);
    let hotProducts = allActive.filter(p => p.isHot === true);

    if (hotProducts.length < 4) {
        const hotIds = new Set(hotProducts.map(p => p.id));
        const remaining = allActive
            .filter(p => !hotIds.has(p.id))
            .map(p => {
                const dv = p.variants[0];
                const disc = dv.originalPrice > 0 ? Math.round((1 - dv.price / dv.originalPrice) * 100) : 0;
                return { product: p, discount: disc };
            })
            .sort((a, b) => b.discount - a.discount)
            .map(x => x.product);
        hotProducts = hotProducts.concat(remaining.slice(0, 6 - hotProducts.length));
    }

    const section = document.getElementById('trendingSection');
    if (hotProducts.length === 0) {
        if (section) section.style.display = 'none';
        return;
    }
    if (section) section.style.display = 'block';

    grid.innerHTML = hotProducts.map(p => renderProductCard(p)).join('');
    if (window.lucide) lucide.createIcons();
}

/* ================================================
   REAL-TIME SYNC ENGINE
   Detects admin changes (stock, price, isHot, etc.)
   from other tabs or periodic localStorage updates
   and instantly re-renders the storefront.
   ================================================ */
let _lastProductHash = localStorage.getItem('getotts_admin_products') || '{}';
let _lastSettingsHash = localStorage.getItem('getotts_admin_settings') || '{}';

// Cross-tab sync: fires when admin panel (another tab) saves changes
window.addEventListener('storage', (e) => {
    if (e.key === 'getotts_admin_products' || e.key === 'getotts_product_version') {
        // Product data changed externally - re-render
        _lastProductHash = e.newValue || '{}';
        renderAllProducts();
        initComboBuilder();
    }
    if (e.key === 'getotts_cart') {
        try { cart = JSON.parse(e.newValue || '[]'); } catch(err) { cart = []; }
        updateCartCount();
        if (document.getElementById('cartDrawer') && document.getElementById('cartDrawer').classList.contains('open')) {
            renderCartDrawer();
        }
    }
    if (e.key === 'getotts_admin_settings') {
        _lastSettingsHash = e.newValue || '{}';
        // Could update site name, social links, etc. dynamically here
    }
});

// Same-tab polling: catches localStorage changes made in the same window
// (e.g. admin panel embedded in same page, or automated stock deductions)
setInterval(() => {
    const currentProducts = localStorage.getItem('getotts_admin_products') || '{}';
    if (currentProducts !== _lastProductHash) {
        // Product data updated - sync storefront
        _lastProductHash = currentProducts;
        renderAllProducts();
        initComboBuilder();
    }
}, 15000); // Check every 15 seconds

function renderCategory(gridId, category) {
    const grid = document.getElementById(gridId);
    if (!grid) return;

    const items = getAllProducts().filter(p => p.category === category);

    grid.innerHTML = items.map(p => renderProductCard(p)).join('');

    // Re-init lucide icons
    if (window.lucide) lucide.createIcons();
}

function renderProductCard(p) {
    try {
        if (!p.variants || !p.variants.length) return '';

        const dv = getDefaultVariant(p);
        if (!dv) return '';

        if (!cardSelections[p.id]) {
            cardSelections[p.id] = {
                accessType: dv.accessType,
                quality: dv.quality,
                duration: dv.duration,
            };
        }
        const sel = cardSelections[p.id];

        const cv = findVariant(p, sel.accessType, sel.quality, sel.duration) || dv;
        const disc = Math.round((1 - cv.price / cv.originalPrice) * 100);

        const qualities = getQualities(p, sel.accessType);
        let qualityHTML = '';
        if (qualities && qualities.length > 1) {
            qualityHTML = `<div class="v-selector v-quality" data-pid="${p.id}">
                ${qualities.map(q => `<button class="v-pill ${q === sel.quality ? 'active' : ''}" data-val="${q}" onclick="changeQuality('${p.id}','${q}')">${q}</button>`).join('')}
            </div>`;
        }

        const durations = getDurations(p, sel.accessType, sel.quality);
        let durationHTML = '';
        if (durations.length > 1) {
            durationHTML = `<div class="v-selector v-duration" data-pid="${p.id}">
                ${durations.map(d => {
                    const label = d >= 24 ? `${d/12}Y` : d >= 12 ? '1Y' : `${d}M`;
                    return `<button class="v-pill ${d === sel.duration ? 'active' : ''}" data-val="${d}" onclick="changeDuration('${p.id}',${d})">${label}</button>`;
                }).join('')}
            </div>`;
        }

        let feats = [];
        if (Array.isArray(p.features)) {
            feats = p.features;
        } else if (p.features && typeof p.features === 'object') {
            feats = p.features[sel.accessType] || p.features[Object.keys(p.features)[0]] || [];
        }

        const hiddenClass = p.isActive === false ? 'admin-hidden' : '';
        const imgContent = p.img
            ? `<img src="${p.img}" alt="${p.name}">`
            : `<span class="p-emoji-large">${p.emoji}</span>`;
        const savedAmt = cv.originalPrice - cv.price;

        return `
        <div class="p-card animate-on-scroll ${hiddenClass}" data-id="${p.id}" data-sku="${cv.sku}">
            <a href="/product/${p.id}" class="p-card-image" style="display:block; text-decoration:none;">
                <div class="p-card-badges">
                    ${p.isHot ? '<span class="p-badge popular">? Most Popular</span>' : ''}
                    <span class="p-badge discount">${disc}% OFF</span>
                </div>
                ${imgContent}
            </a>
            <div class="p-card-body">
                <a href="/product/${p.id}" style="text-decoration:none; display:block;"><div class="p-name">${p.name}</div></a>
                
                ${qualityHTML}
                ${durationHTML}
                
                <ul class="p-features">
                    ${feats.slice(0, 3).map(f => `<li>${f}</li>`).join('')}
                </ul>
                
                <div class="p-bottom">
                    <div>
                        <div class="p-price-old">?${cv.originalPrice.toLocaleString('en-IN')}</div>
                        <div class="p-price">?${cv.price.toLocaleString('en-IN')}<small>/${cv.durationLabel.toLowerCase()}</small><span class="p-savings">Save ?${savedAmt.toLocaleString('en-IN')}</span></div>
                    </div>
                    <div class="p-buttons">
                        <button class="cart-add-btn" onclick="addToCart('${cv.sku}')" title="Add to Cart">
                            <i data-lucide="shopping-cart"></i>
                        </button>
                        <button class="buy-btn" onclick="buyProduct('${cv.sku}')">Buy ${p.name}</button>
                    </div>
                </div>
            </div>
        </div>`;
    } catch(e) {
        console.warn('Error rendering product', p.id, e);
        return '';
    }
}


/* ================================================
   VARIANT CHANGERS
   ================================================ */
function changeAccess(pid, accessType) {
    cardSelections[pid].accessType = accessType;
    // Reset quality to first available for this access type
    const p = getAllProducts().find(x => x.id === pid);
    if (p) {
        const quals = getQualities(p, accessType);
        cardSelections[pid].quality = quals ? quals[0] : null;
        // Reset duration to first available
        const durs = getDurations(p, accessType, cardSelections[pid].quality);
        if (!durs.includes(cardSelections[pid].duration)) {
            cardSelections[pid].duration = durs[0];
        }
    }
    renderAllProducts();
}

function changeQuality(pid, quality) {
    cardSelections[pid].quality = quality;
    const p = getAllProducts().find(x => x.id === pid);
    if (p) {
        const durs = getDurations(p, cardSelections[pid].accessType, quality);
        if (!durs.includes(cardSelections[pid].duration)) {
            cardSelections[pid].duration = durs[0];
        }
    }
    renderAllProducts();
}

function changeDuration(pid, duration) {
    cardSelections[pid].duration = duration;
    renderAllProducts();
}

/* ================================================
   CART ? SKU-based with proper stacking
   ================================================ */
let cart = JSON.parse(localStorage.getItem('getotts_cart') || '[]');

// Migrate old cart format if needed
if (cart.length && cart[0].id && !cart[0].sku) {
    cart = []; // Clear old format
    localStorage.setItem('getotts_cart', '[]');
}

function addToCart(sku) {
    const result = getVariant(sku);
    if (!result) return;
    const { product, variant } = result;

    const existing = cart.find(i => i.sku === sku);
    if (existing) {
        existing.qty += 1;
    } else {
        cart.push({ sku, qty: 1 });
    }

    localStorage.setItem('getotts_cart', JSON.stringify(cart));
    updateCartCount();
    openCart();

    // Toast
    document.getElementById('toastName').textContent = product.name;
    document.getElementById('toastMsg').textContent = `${variant.durationLabel} added to cart ??`;
    const toast = document.getElementById('toast');
    toast.classList.add('show');
    setTimeout(() => toast.classList.remove('show'), 3000);
}

function updateCartCount() {
    const badge = document.getElementById('cartBadge');
    
    let total = 0;
    let count = 0;
    cart.forEach(item => {
        count += item.qty;
        const result = getVariant(item.sku);
        if (result && result.variant) {
            total += result.variant.price * item.qty;
        }
    });

    if (badge) {
        badge.textContent = count;
        badge.style.display = count > 0 ? 'flex' : 'none';

        badge.classList.remove('bounce');
        void badge.offsetWidth;
        badge.classList.add('bounce');
    }

    document.querySelectorAll('#cartTotal, .cart-price').forEach(el => {
        if (el.tagName.toLowerCase() === 'strong') {
            el.textContent = '?' + total.toLocaleString('en-IN');
        } else {
            el.textContent = '?' + total.toLocaleString('en-IN') + (total % 1 === 0 ? '.00' : '');
        }
    });
}

/* ================================================
   CART DRAWER
   ================================================ */
function openCart() {
    const drawer = document.getElementById('cartDrawer');
    const overlay = document.getElementById('cartOverlay');
    if (drawer) { drawer.classList.add('open'); renderCartDrawer(); }
    if (overlay) overlay.classList.add('open');
}
function closeCart() {
    const drawer = document.getElementById('cartDrawer');
    const overlay = document.getElementById('cartOverlay');
    if (drawer) drawer.classList.remove('open');
    if (overlay) overlay.classList.remove('open');
}

function renderCartDrawer() {
    const body = document.getElementById('cartDrawerBody');
    const footer = document.getElementById('cartDrawerFooter');
    if (!body || !footer) return;

    if (cart.length === 0) {
        body.innerHTML = '<div class="cart-empty"><span>??</span><p>Your cart is empty</p></div>';
        footer.style.display = 'none';
        return;
    }

    let total = 0;
    body.innerHTML = cart.map((item, idx) => {
        const result = getVariant(item.sku);
        if (!result) return '';
        const { product, variant } = result;
        const lineTotal = variant.price * item.qty;
        total += lineTotal;

                const imgSrc = product.img ? (product.img.startsWith('http') || product.img.startsWith('/') ? product.img : '/' + product.img) : '';
                return `
            <div class="cart-item">
                <span class="cart-item-emoji">${imgSrc ? `<img src="${imgSrc}" alt="${product.name}" style="width:32px;height:32px;border-radius:8px;object-fit:cover;">` : product.emoji}</span>
                <div class="cart-item-info">
                    <div class="cart-item-name">${product.name}</div>
                    <div class="cart-item-plan">${variant.durationLabel}${variant.quality ? ' ? ' + variant.quality : ''}</div>
                </div>
                <div class="cart-item-qty">
                    <button class="qty-btn" onclick="changeQty(${idx}, -1)">?</button>
                    <span>${item.qty}</span>
                    <button class="qty-btn" onclick="changeQty(${idx}, 1)">+</button>
                </div>
                <span class="cart-item-price">?${lineTotal.toLocaleString('en-IN')}</span>
                <button class="cart-item-remove" onclick="removeFromCart(${idx})" title="Remove">?</button>
            </div>
        `;
    }).join('');

    document.getElementById('cartTotal').textContent = '?' + total.toLocaleString('en-IN');
    footer.style.display = 'block';
}

function changeQty(index, delta) {
    cart[index].qty += delta;
    if (cart[index].qty <= 0) {
        cart.splice(index, 1);
    }
    localStorage.setItem('getotts_cart', JSON.stringify(cart));
    updateCartCount();
    renderCartDrawer();
}

function removeFromCart(index) {
    cart.splice(index, 1);
    localStorage.setItem('getotts_cart', JSON.stringify(cart));
    updateCartCount();
    renderCartDrawer();
}

function checkoutCart() {
    if (cart.length === 0) return;
    const skus = cart.map(i => `${i.sku}:${i.qty}`).join(',');
    closeCart();
    sessionStorage.setItem('checkoutState', JSON.stringify({ cart: skus }));
    window.location.href = `/checkout`;
}

// Wire cart button
document.addEventListener('DOMContentLoaded', () => {
    updateCartCount();
    const cartBtn = document.getElementById('cartBtn');
    if (cartBtn) cartBtn.addEventListener('click', openCart);
});

function buyProduct(sku) {
    sessionStorage.setItem('checkoutState', JSON.stringify({ sku: sku }));
    window.location.href = `/checkout`;
}

function buyCombo() {
    if (picked.size < 3) return;
    const ids = Array.from(picked).join(',');
    sessionStorage.setItem('checkoutState', JSON.stringify({ combo: ids }));
    window.location.href = `/checkout`;
}

/* ================================================
   PLAN SWITCH (legacy ? now changes access type globally)
   ================================================ */
function initPlanSwitch() {
    document.querySelectorAll('.plan-switch').forEach(sw => {
        sw.querySelectorAll('.ps-btn').forEach(btn => {
            btn.addEventListener('click', () => {
                sw.querySelectorAll('.ps-btn').forEach(b => b.classList.remove('active'));
                btn.classList.add('active');
                const plan = btn.dataset.plan;
                // Update all card selections to this access type
                for (const pid of Object.keys(cardSelections)) {
                    const p = getAllProducts().find(x => x.id === pid);
                    if (p) {
                        const types = getAccessTypes(p);
                        if (types.includes(plan)) {
                            cardSelections[pid].accessType = plan;
                            const quals = getQualities(p, plan);
                            cardSelections[pid].quality = quals ? quals[0] : null;
                            const durs = getDurations(p, plan, cardSelections[pid].quality);
                            if (!durs.includes(cardSelections[pid].duration)) {
                                cardSelections[pid].duration = durs[0];
                            }
                        }
                    }
                }
                renderAllProducts();
            });
        });
    });
}

/* ================================================
   COMBO BUILDER
   ================================================ */
let picked = new Set();

function initComboBuilder() {
    const picker = document.getElementById('comboPicker');
    if (!picker) return;

    const comboProducts = getAllProducts().filter(p => ['streaming', 'music', 'ai'].includes(p.category));

    picker.innerHTML = comboProducts.map(p => {
        const dv = getDefaultVariant(p);
        if (!dv) return '';
        return `
        <div class="cp-card" data-id="${p.id}" onclick="toggleCombo('${p.id}')">
            <span class="cp-emoji">${p.img ? `<img src="${p.img}" alt="${p.name}" style="width:28px;height:28px;border-radius:6px;object-fit:cover;">` : p.emoji}</span>
            <span class="cp-name">${p.name}</span>
            <span class="cp-price">?${dv.price}/mo</span>
        </div>`;
    }).join('');
}

function toggleCombo(id) {
    picked.has(id) ? picked.delete(id) : picked.add(id);

    document.querySelectorAll('.cp-card').forEach(c => {
        c.classList.toggle('picked', picked.has(c.dataset.id));
    });

    updateComboReceipt();
}

function updateComboReceipt() {
    const itemsEl = document.getElementById('comboItems');
    const totals = document.getElementById('comboTotals');
    const buyBtn = document.getElementById('comboBuy');

    if (picked.size < 3) {
        itemsEl.innerHTML = `<p class="combo-empty">Pick ${3 - picked.size} more platform${picked.size < 2 ? 's' : ''}</p>`;
        totals.style.display = 'none';
        buyBtn.style.display = 'none';
        return;
    }

    let subtotal = 0;
    let rows = [];
    picked.forEach(id => {
        const p = getAllProducts().find(x => x.id === id);
        if (p) {
            const dv = getDefaultVariant(p);
            if (dv) {
                subtotal += dv.price;
                rows.push(`<div class="ci-row"><span>${p.img ? '<img src="'+p.img+'" style="width:16px;height:16px;border-radius:4px;vertical-align:middle;margin-right:4px;">' : p.emoji} ${p.name}</span><span>?${dv.price}</span></div>`);
            }
        }
    });

    const discPct = picked.size >= 10 ? 25 : picked.size >= 7 ? 20 : picked.size >= 5 ? 15 : 10;
    const discAmt = Math.round(subtotal * discPct / 100);
    const total = subtotal - discAmt;

    itemsEl.innerHTML = rows.join('');
    document.getElementById('comboSubtotal').textContent = `?${subtotal}`;
    document.getElementById('comboDiscount').textContent = `-?${discAmt} (${discPct}%)`;
    document.getElementById('comboTotal').textContent = `?${total}`;

    totals.style.display = 'block';
    buyBtn.style.display = 'flex';

    if (window.lucide) lucide.createIcons();
}

